  "meta": {
    "intent": "To create a hyper-realistic, surreal editorial photograph blending ecstatic emotional release with an impossible, tactile structural effect within a symmetrical void.",
    "priorities": "Absolute framing symmetry, warm vibrant volumetric lighting, hyper-realistic skin texture, and the convincing practical effect of melting liquid amber/glass.",
    "device_profile": "High-Resolution Medium Format Digital / Cinematic Analog Hybrid"
  },
  "frame": {
    "aspect": "4:5",
    "composition": "The Grand Symmetrical Centering",
    "layout": "Subject dead center, architectural lines converging perfectly in the middle, head tilted back toward the upper edge of the frame.",
    "camera_angle": "Dead-on straight, waist-up portrait",
    "tilt_roll_degrees": "0"
  },
  "subject": {
    "gender": "Female",
    "identity": "The Protagonist",
    "demographics": "Ageless, ethereal high-fashion archetype",
    "face": "Eyes closed in pleasure, mouth slightly parted, glistening skin with hyper-detailed pores and micro-sweat.",
    "hair": "Whipping dramatically and symmetrically upwards and backwards, caught in a strong wind.",
    "body": "Shoulders relaxed but perfectly centered, neck exposed and elongated in a pose of complete surrender.",
    "expression": "Euphoric trance, pure passionate release and self-abandonment.",
    "pose": "Dynamic head thrown back, facing upward into the warm light, embracing the void with all senses."
  },
  "wardrobe_accessories": {
    "garments": [
      {
        "item": "Avant-garde turtleneck top",
        "material": "Matte neoprene or heavy cotton",
        "color": "Stark pristine white",
        "fit": "Tailored, structurally rigid"
      }
    ],
    "accessories": [
      {
        "item": "Surreal dripping eyewear structure",
        "color": "Warm translucent amber and gold",
        "material": "Melting liquid glass, glowing resin, defying gravity",
        "brand_style": "Impossible High-Budget Practical Effect"
      }
    ]
  },
  "environment": {
    "setting": "A colossal, perfectly symmetrical obsidian amphitheater or altar situated at the very edge of an endless void.",
    "surfaces": "Highly polished dark stone, reflective black obsidian.",
    "depth": "Infinite deep background transitioning into a luminous, hazy emptiness.",
    "atmosphere": "Heavy, warm atmospheric haze, wind rushing toward the camera.",
    "lens_interaction": "Vibrant, warm bokeh spheres forming in the hazy background void."
  },
  "lighting": {
    "key": "Symmetrical dual warm key lights from the front-side angles.",
    "fill": "Warm, glowing volumetric bounce from the void behind.",
    "rim": "Intense, golden rim light catching the edges of the hair and the melting amber glasses.",
    "shadows": "Deep, rich, and perfectly symmetrical.",
    "color_temperature": "Warm, vibrant amber and golden hour tones (3200K - 4000K).",
    "sensor_flare": "Subtle warm cinematic flares originating from the liquid refractions."
  },
  "camera": {
    "lens_type": "Ultra-Wide Prime",
    "focal_length": "24mm",
    "aperture": "f/1.4",
    "focus": "Tack sharp on the lips, skin pores, and the dripping liquid glass, with the void falling into extreme bokeh.",
    "sensor_format": "Medium Format Hasselblad H6D-100c",
    "perspective_distortion": "Slight wide-angle exaggeration of the surrounding architectural symmetry."
  },
  "post_processing": {
    "color": "Rich, vibrant golden tones with deep crushed obsidian blacks.",
    "tonality": "High-contrast cinematic editorial.",
    "texture": "Kodak Portra 800 organic film grain, preserving authentic skin imperfections.",
    "digital_sharpening": "Zero digital sharpening, maintaining analog softness in the out-of-focus areas.",
    "chromatic_aberration": "Subtle organic chromatic aberration at the extreme edges of the ultra-wide frame."
  },
  "negative_specifications": [
    "No neon lights",
    "No digital painting artifacts",
    "No asymmetrical framing",
    "No flat studio lighting",
    "No modern urban cityscapes",
    "No plastic or over-retouched AI skin",
    "No open eyes"
  ]
}

